### Type Guards

Type guards are expressions that perform runtime checks to guarantee the type of a value.

### typeof Type Guard

```typescript
function process(value: string | number): void {
  if (typeof value === "string") {
    console.log(value.toUpperCase());
  } else {
    console.log(value.toFixed(2));
  }
}
```

### instanceof Type Guard

```typescript
class Dog {
  bark(): void { console.log("Woof!"); }
}

class Cat {
  meow(): void { console.log("Meow!"); }
}

type Animal = Dog | Cat;

function makeSound(animal: Animal): void {
  if (animal instanceof Dog) {
    animal.bark();
  } else {
    animal.meow();
  }
}
```

### in Type Guard

```typescript
interface Bird {
  fly(): void;
}

interface Fish {
  swim(): void;
}

type Pet = Bird | Fish;

function move(pet: Pet): void {
  if ("fly" in pet) {
    pet.fly();
  } else {
    pet.swim();
  }
}
```

### User-Defined Type Guards

```typescript
interface Cat {
  meow: () => void;
}

function isCat(pet: unknown): pet is Cat {
  return (pet as Cat).meow !== undefined;
}

function handlePet(pet: unknown): void {
  if (isCat(pet)) {
    pet.meow(); // TypeScript knows pet is Cat here
  }
}
```

### Type Predicate Syntax

```
function functionName(arg: Type): arg is SpecificType {
  return boolean;
}
```

> **Key Point:** `typeof` works with primitives, `instanceof` with classes, and custom predicates for complex logic.

codeExample:
// typeof guard
function double(value: string | number): string | number {
  if (typeof value === "number") {
    return value * 2;
  }
  return value + value;
}

// Custom type guard
interface Admin {
  role: "admin";
  permissions: string[];
}

interface User {
  role: "user";
  name: string;
}

type Account = Admin | User;

function isAdmin(account: Account): account is Admin {
  return account.role === "admin";
}

function getPermissions(account: Account): string[] {
  if (isAdmin(account)) {
    return account.permissions; // narrowed
  }
  return [];
}
